import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import { subjectAPI } from '../services/api';

const initialForm = {
  code: '',
  name: '',
  department: '',
  semester: 1,
  credits: 3,
  studentsEnrolled: '',
  preferredSlot: 'any',
  duration: 3,
};

const Subjects = () => {
  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState(initialForm);

  const fetchSubjects = async () => {
    try {
      setLoading(true);
      const response = await subjectAPI.getAll();
      setSubjects(response.data || []);
    } catch (error) {
      toast.error('Failed to load subjects');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSubjects();
  }, []);

  const onChange = (event) => {
    const { name, value } = event.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleAddSubject = async (event) => {
    event.preventDefault();
    try {
      setSubmitting(true);
      const payload = {
        ...formData,
        semester: Number(formData.semester),
        credits: Number(formData.credits),
        duration: Number(formData.duration),
        studentsEnrolled: formData.studentsEnrolled
          .split(',')
          .map((studentId) => studentId.trim())
          .filter(Boolean),
      };
      await subjectAPI.add(payload);
      toast.success('Subject added successfully');
      setFormData(initialForm);
      fetchSubjects();
    } catch (error) {
      toast.error(error.response?.data?.error || 'Failed to add subject');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteSubject = async (code) => {
    try {
      await subjectAPI.delete(code);
      toast.success('Subject deleted');
      fetchSubjects();
    } catch (error) {
      toast.error('Failed to delete subject');
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Subjects</h1>
        <p className="text-gray-600">Manage subjects and preferences for scheduling.</p>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Add Subject</h2>
        <form onSubmit={handleAddSubject} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <input
            className="input-field"
            name="code"
            placeholder="Subject Code"
            value={formData.code}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="name"
            placeholder="Subject Name"
            value={formData.name}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="department"
            placeholder="Department"
            value={formData.department}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="number"
            min="1"
            name="semester"
            placeholder="Semester"
            value={formData.semester}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="number"
            min="1"
            name="credits"
            placeholder="Credits"
            value={formData.credits}
            onChange={onChange}
          />
          <input
            className="input-field"
            type="number"
            min="1"
            name="duration"
            placeholder="Duration (hours)"
            value={formData.duration}
            onChange={onChange}
          />
          <select
            className="input-field"
            name="preferredSlot"
            value={formData.preferredSlot}
            onChange={onChange}
          >
            <option value="any">Any slot</option>
            <option value="morning">Morning</option>
            <option value="afternoon">Afternoon</option>
          </select>
          <input
            className="input-field md:col-span-2"
            name="studentsEnrolled"
            placeholder="Enrolled Student IDs (comma separated)"
            value={formData.studentsEnrolled}
            onChange={onChange}
          />
          <div className="md:col-span-2 lg:col-span-3">
            <button type="submit" className="btn-primary" disabled={submitting}>
              {submitting ? 'Adding...' : 'Add Subject'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6 overflow-x-auto">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-gray-800">Subject List</h2>
          <button onClick={fetchSubjects} className="btn-secondary">
            Refresh
          </button>
        </div>

        {loading ? (
          <p className="text-gray-500">Loading subjects...</p>
        ) : subjects.length === 0 ? (
          <p className="text-gray-500">No subjects added yet.</p>
        ) : (
          <table className="min-w-full">
            <thead>
              <tr className="table-header">
                <th className="px-4 py-3 text-left">Code</th>
                <th className="px-4 py-3 text-left">Name</th>
                <th className="px-4 py-3 text-left">Department</th>
                <th className="px-4 py-3 text-left">Semester</th>
                <th className="px-4 py-3 text-left">Slot</th>
                <th className="px-4 py-3 text-left">Students</th>
                <th className="px-4 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {subjects.map((subject) => (
                <tr key={subject.code} className="table-row">
                  <td className="px-4 py-3 font-semibold">{subject.code}</td>
                  <td className="px-4 py-3">{subject.name}</td>
                  <td className="px-4 py-3">{subject.department}</td>
                  <td className="px-4 py-3">{subject.semester}</td>
                  <td className="px-4 py-3 capitalize">{subject.preferredSlot || 'any'}</td>
                  <td className="px-4 py-3">{(subject.studentsEnrolled || []).length}</td>
                  <td className="px-4 py-3">
                    <button
                      onClick={() => handleDeleteSubject(subject.code)}
                      className="btn-danger"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Subjects;
